<?php
declare(strict_types=1);
namespace Ostoya\ShoppingList\Model\Resolver; use Magento\Framework\GraphQl\Config\Element\Field;use Magento\Framework\GraphQl\Query\ResolverInterface;use Magento\Framework\GraphQl\Schema\Type\ResolveInfo;use Ostoya\ShoppingList\Model\Service\ShoppingListService;
class UpdateShoppingListItemQty implements ResolverInterface{public function __construct(private readonly CustomerContext $customerContext,private readonly ShoppingListService $service,private readonly ResolverDataFormatter $formatter){} public function resolve(Field $field,$context,ResolveInfo $info,array $value=null,array $args=null): array{$item=$this->service->updateItemQty($this->customerContext->getCustomerId($context),(int)$args['input']['item_id'],(float)$args['input']['qty']);$list=$this->service->getCustomerListById($this->customerContext->getCustomerId($context),(int)$item->getData('list_id'));return ['success'=>true,'message'=>'Shopping list item updated.','item'=>$this->formatter->formatItem($item),'list'=>$this->formatter->formatList($list,[])];}}
